```cpp
// 閉區間 [left, right] 二分模板
int search(vector<int>& nums, int target) {
    int left = 0, right = nums.size() - 1; // 搜尋範圍 [left, right]
    while (left <= right) {
        int mid = left + (right - left) / 2; // 防溢位寫法
        if (nums[mid] == target) {
            return mid;
        } else if (nums[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return -1;
}
```
